"""Cron expression parser for standard 5-field cron schedules.

This module provides a readable, decomposed parser that handles
wildcards, ranges, lists, and steps. It returns a structured result
with a human-readable description.

Design priorities: small well-named functions, shared single-field
parser, rich dataclass result, type hints everywhere, clear errors.
"""

from __future__ import annotations

from dataclasses import dataclass
from typing import List, Optional, Set, Tuple


# ---------------------------------------------------------------------------
# Constants (single source of truth for field bounds and labels)
# ---------------------------------------------------------------------------

DAY_NAMES: Tuple[str, ...] = (
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday",
)

MONTH_NAMES: Tuple[str, ...] = (
    "",  # 1-based
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December",
)

# (name, min, max) for the five fields. Using a single tuple keeps
# parse_cron simple and eliminates parallel-list maintenance.
FIELD_SPECS: Tuple[Tuple[str, int, int], ...] = (
    ("minute", 0, 59),
    ("hour", 0, 23),
    ("day_of_month", 1, 31),
    ("month", 1, 12),
    ("day_of_week", 0, 6),
)


# ---------------------------------------------------------------------------
# Tiny leaf utilities (pure, no side effects, trivial to understand)
# ---------------------------------------------------------------------------

def _parse_int(value: str, context: str) -> int:
    """Parse a token to int or raise a context-rich error."""
    value = value.strip()
    try:
        return int(value)
    except ValueError:
        raise ValueError(f"Invalid {context} '{value}': expected an integer") from None


def _validate_in_range(val: int, min_val: int, max_val: int, context: str) -> None:
    """Raise a clear error when a value falls outside its field's legal range."""
    if val < min_val or val > max_val:
        raise ValueError(
            f"{context} value {val} is outside the allowed range {min_val}-{max_val}"
        )


def _ordinal(n: int) -> str:
    """Return a day ordinal such as '1st', '2nd', '3rd', or '4th'."""
    if 11 <= (n % 100) <= 13:
        return f"{n}th"
    suffix = {1: "st", 2: "nd", 3: "rd"}.get(n % 10, "th")
    return f"{n}{suffix}"


def _format_english_list(items: List[str]) -> str:
    """Turn ['Monday', 'Wednesday', 'Friday'] into 'Monday, Wednesday, and Friday'."""
    if len(items) == 0:
        return ""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + f", and {items[-1]}"


# ---------------------------------------------------------------------------
# Data model (declared early so the rest of the file reads top-down)
# ---------------------------------------------------------------------------

@dataclass(frozen=True)
class FieldPart:
    """One atomic (non-comma) piece of a field: '*', '1-5', '*/15', '1-30/5', or '42'.

    Stores the declared bounds and step so description logic can produce
    natural phrases such as "Monday through Friday" without re-parsing strings.
    """

    original: str
    start: int
    end: int
    step: int  # 1 means contiguous (single value or simple range)

    def get_values(self) -> List[int]:
        """Materialize the concrete integers matched by this part."""
        return list(range(self.start, self.end + 1, self.step))

    @property
    def is_single(self) -> bool:
        return self.start == self.end and self.step == 1

    @property
    def is_step(self) -> bool:
        return self.step > 1


@dataclass(frozen=True)
class CronField:
    """Structured view of one cron field after parsing.

    The combination of original text, the list of structural parts, and the
    flattened sorted values lets both execution (if ever needed) and the
    describe() method stay simple and readable.
    """

    original: str
    parts: Tuple[FieldPart, ...]
    values: Tuple[int, ...]  # always sorted and deduplicated
    min_value: int
    max_value: int

    @property
    def is_wildcard(self) -> bool:
        """True only when the author literally wrote '*'."""
        return self.original == "*"

    @property
    def covers_all(self) -> bool:
        """True when every legal value for the field is accepted."""
        return len(self.values) == (self.max_value - self.min_value + 1)

    @property
    def is_single_value(self) -> bool:
        return len(self.values) == 1

    def get_single_value(self) -> int:
        if not self.is_single_value:
            raise ValueError(
                f"Field '{self.original}' does not contain exactly one value"
            )
        return self.values[0]

    def get_step(self) -> Optional[int]:
        """Return the step size N for patterns that look like '*/N' or '0-59/N'.

        Returns None for lists, ordinary ranges, or stepped sub-ranges
        that do not cover the field's full legal span.
        """
        if len(self.parts) != 1:
            return None
        p = self.parts[0]
        if p.step <= 1:
            return None
        if p.start == self.min_value and p.end == self.max_value:
            return p.step
        return None

    def get_range(self) -> Optional[Tuple[int, int]]:
        """Return (start, end) when the field is exactly one simple range (no step)."""
        if len(self.parts) != 1:
            return None
        p = self.parts[0]
        if p.step != 1 or p.start == p.end:
            return None
        return (p.start, p.end)


@dataclass(frozen=True)
class CronSchedule:
    """The result of parsing a 5-field cron expression.

    Use .describe() for the human readable sentence. The individual
    CronField objects give access to both the original text and the
    concrete allowed values when needed.
    """

    expression: str
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        """Return a natural English description matching the required style."""
        return _describe_schedule(self)


# ---------------------------------------------------------------------------
# Description helpers (operate only on already-parsed objects)
# ---------------------------------------------------------------------------

def _is_every_minute(schedule: CronSchedule) -> bool:
    """True for the literal '* * * * *' (or any form that covers everything)."""
    return all(
        f.is_wildcard
        for f in (
            schedule.minute,
            schedule.hour,
            schedule.day_of_month,
            schedule.month,
            schedule.day_of_week,
        )
    )


def _is_every_n_minutes(schedule: CronSchedule) -> bool:
    step = schedule.minute.get_step()
    return (
        step is not None
        and schedule.hour.is_wildcard
        and schedule.day_of_month.is_wildcard
        and schedule.month.is_wildcard
        and schedule.day_of_week.is_wildcard
    )


def _is_every_n_hours_on_the_hour(schedule: CronSchedule) -> bool:
    step = schedule.hour.get_step()
    return (
        step is not None
        and schedule.minute.is_single_value
        and schedule.minute.get_single_value() == 0
        and schedule.day_of_month.is_wildcard
        and schedule.month.is_wildcard
        and schedule.day_of_week.is_wildcard
    )


def _describe_time(minute: CronField, hour: CronField) -> str:
    """Produce the leading time phrase: '12:00', 'midnight', 'every 15 minutes', etc."""
    m_step = minute.get_step()
    if m_step is not None and hour.is_wildcard:
        return "every minute" if m_step == 1 else f"every {m_step} minutes"

    h_step = hour.get_step()
    if h_step is not None and minute.is_single_value and minute.get_single_value() == 0:
        return "every hour, on the hour" if h_step == 1 else f"every {h_step} hours, on the hour"

    if minute.is_single_value and hour.is_single_value:
        h = hour.get_single_value()
        m = minute.get_single_value()
        if h == 0 and m == 0:
            return "midnight"
        return f"{h:02d}:{m:02d}"

    # Less common but still useful patterns
    if hour.is_single_value and minute.covers_all:
        h = hour.get_single_value()
        return f"every minute of hour {h:02d}"

    if minute.is_single_value and hour.is_wildcard:
        m = minute.get_single_value()
        return f":{m:02d} past every hour"

    return "specified times"


def _describe_weekdays(dow: CronField) -> str:
    """'Monday through Friday', 'Monday, Wednesday, and Friday', or ''."""
    if dow.is_wildcard or dow.covers_all:
        return ""

    rng = dow.get_range()
    if rng is not None:
        start, end = rng
        if 0 <= start <= end <= 6:
            return f"{DAY_NAMES[start]} through {DAY_NAMES[end]}"

    vals = list(dow.values)
    if vals == [0, 6]:
        return "Saturday and Sunday"

    names = [DAY_NAMES[v] for v in vals]
    return _format_english_list(names)


def _describe_monthdays(dom: CronField) -> str:
    """'the 1st', 'the 1st and the 15th', or ''."""
    if dom.is_wildcard or dom.covers_all:
        return ""

    rng = dom.get_range()
    if rng is not None:
        a, b = rng
        return f"the {_ordinal(a)} through the {_ordinal(b)}"

    vals = list(dom.values)
    if len(vals) == 1:
        return f"the {_ordinal(vals[0])}"

    return _format_english_list([f"the {_ordinal(v)}" for v in vals])


def _describe_months(month: CronField) -> str:
    """'January', 'June through August', 'January and March', or ''."""
    if month.is_wildcard or month.covers_all:
        return ""

    rng = month.get_range()
    if rng is not None:
        a, b = rng
        if 1 <= a <= b <= 12:
            return f"{MONTH_NAMES[a]} through {MONTH_NAMES[b]}"

    names = [MONTH_NAMES[v] for v in month.values]
    return _format_english_list(names)


def _describe_occurrence(dom: CronField, month: CronField, dow: CronField) -> str:
    """The trailing 'when' clause: 'on Monday through Friday' or 'on the 1st of every month'."""
    dow_str = _describe_weekdays(dow)
    dom_str = _describe_monthdays(dom)
    mon_str = _describe_months(month)

    if dow_str and not dom_str:
        if mon_str:
            return f"on {dow_str} in {mon_str}"
        return f"on {dow_str}"

    if dom_str and not dow_str:
        month_ref = mon_str if mon_str else "every month"
        return f"on {dom_str} of {month_ref}"

    if dow_str and dom_str:
        # Both constraints present (cron treats them as OR). Keep the phrasing readable.
        if mon_str:
            return f"on {dom_str} of {mon_str} and on {dow_str}"
        return f"on {dom_str} of the month and on {dow_str}"

    if mon_str:
        return f"in {mon_str}"

    return ""


