    """Assemble the final sentence. Special cases first for the exact example phrasing."""
    # Canonical special cases that must match the prompt examples exactly.
    if _is_every_minute(schedule):
        return "Every minute"

    if _is_every_n_minutes(schedule):
        step = schedule.minute.get_step()
        return f"Every {step} minutes"

    if _is_every_n_hours_on_the_hour(schedule):
        step = schedule.hour.get_step()
        return f"Every {step} hours, on the hour"

