) -> FieldPart:
    """Handle a plain range such as 1-5 or 10-20."""
    if part.count("-") != 1:
        raise ValueError(f"Malformed range expression '{part}' in {field_name}")

    start, end = _extract_range_bounds(part, min_val, max_val, field_name)
    return FieldPart(original=part, start=start, end=end, step=1)


def _extract_range_bounds(
    range_text: str, min_val: int, max_val: int, field_name: str
) -> Tuple[int, int]:
    """Shared helper that parses and validates A-B bounds for both ranges and steps."""
    if range_text.count("-") != 1:
        raise ValueError(f"Invalid range syntax '{range_text}' in {field_name}")

    a_str, b_str = [p.strip() for p in range_text.split("-", 1)]
    start = _parse_int(a_str, "range start")
    end = _parse_int(b_str, "range end")

    if start > end:
        raise ValueError(f"Start {start} is greater than end {end} in range '{range_text}'")

    if start < min_val or end > max_val:
        raise ValueError(
            f"Range {start}-{end} is outside the allowed bounds {min_val}-{max_val} "
            f"for {field_name}"
        )
    return start, end


def parse_field(
    spec: str, min_val: int, max_val: int, field_name: str
) -> CronField:
    """Parse any one of the five cron fields (the single shared implementation).

    Lists are supported by splitting on commas and delegating each piece to
    the atomic _parse_field_part routine. No field-specific parsing code exists.
    """
    spec = spec.strip()
    if not spec:
        raise ValueError(f"{field_name} field cannot be empty")

    raw_parts = [p.strip() for p in spec.split(",") if p.strip()]
    if not raw_parts:
        raise ValueError(f"No valid segments found in {field_name} field: '{spec}'")

    parts: List[FieldPart] = []
    all_values: Set[int] = set()

    for raw in raw_parts:
        fp = _parse_field_part(raw, min_val, max_val, field_name)
        parts.append(fp)
        all_values.update(fp.get_values())

    return CronField(
        original=spec,
        parts=tuple(parts),
        values=tuple(sorted(all_values)),
        min_value=min_val,
        max_value=max_val,
    )


def _split_expression(expression: str) -> List[str]:
    """Validate overall shape and return the five fields (whitespace normalized)."""
    if not isinstance(expression, str):
        raise ValueError("Cron expression must be a string")
    if not expression or not expression.strip():
        raise ValueError("Cron expression cannot be empty")

    # Collapse any amount of whitespace so that later reconstruction is stable.
    normalized = " ".join(expression.strip().split())
    parts = normalized.split()

    if len(parts) != 5:
        raise ValueError(
            f"Cron expression must have exactly 5 fields "
            f"(minute hour day_of_month month day_of_week), "
            f"got {len(parts)}: {expression!r}"
        )
    return parts


def parse_cron(expression: str) -> CronSchedule:
    """Parse a standard 5-field cron expression and return the structured result."""
    parts = _split_expression(expression)
    normalized = " ".join(parts)

    parsed_fields: List[CronField] = []
    for (name, minv, maxv), part in zip(FIELD_SPECS, parts):
        try:
            fld = parse_field(part, minv, maxv, name)
            parsed_fields.append(fld)
        except ValueError as exc:
            # Wrap so the caller immediately knows which of the five fields failed.
            raise ValueError(f"Error in {name} field: {exc}") from exc

    return CronSchedule(
        expression=normalized,
        minute=parsed_fields[0],
        hour=parsed_fields[1],
        day_of_month=parsed_fields[2],
        month=parsed_fields[3],
        day_of_week=parsed_fields[4],
    )


# ---------------------------------------------------------------------------
# Convenience entry point for manual testing
