if __name__ == "__main__":
    import sys

    if len(sys.argv) > 1:
        expr = " ".join(sys.argv[1:])
        try:
            sched = parse_cron(expr)
            print(f"Expression: {sched.expression}")
            print(f"Description: {sched.describe()}")
            print(
                "Values -> "
                f"min={list(sched.minute.values)} "
                f"hour={list(sched.hour.values)} "
                f"dom={list(sched.day_of_month.values)} "
                f"mon={list(sched.month.values)} "
                f"dow={list(sched.day_of_week.values)}"
            )
        except ValueError as err:
            print(f"Error: {err}")
    else:
        print("Usage: python -m cron_parser '<cron expression>'")
        print("Example: python -m cron_parser '0 12 * * 1-5'")
